package main

import (
	"encoding/binary"
	"encoding/hex"
	"log"
	"net"
	"regexp"
)

// hexPayload berisi string heksadesimal dari log Anda.
// RC 00
// const hexPayload = ``
// RC 51
const hexPayload = ``

// 2. Buat regex untuk menghapus semua yang bukan karakter HEX
var re = regexp.MustCompile(`[^0-9a-fA-F]+`)

func main() {
	// 3. Bersihkan string HEX menggunakan regex
	cleanHex := re.ReplaceAllString(hexPayload, "")

	// 4. Ubah string HEX yang sudah bersih menjadi slice of bytes
	payloadBytes, err := hex.DecodeString(cleanHex)
	if err != nil {
		log.Fatalf("Gagal mengubah HEX string: %v", err)
	}

	// 5. Hubungkan ke server TCP Anda
	conn, err := net.Dial("tcp", "localhost:3333")
	if err != nil {
		log.Fatalf("Gagal terhubung ke server: %v", err)
	}
	defer conn.Close()

	// 6. Siapkan header 2-byte yang berisi panjang payload
	length := len(payloadBytes)
	header := make([]byte, 2)
	binary.BigEndian.PutUint16(header, uint16(length))
	log.Printf("Menyiapkan payload dengan panjang %d bytes", length)

	// 7. Gabungkan header dan payload
	messageToSend := append(header, payloadBytes...)

	// 8. Kirim pesan ke server
	_, err = conn.Write(messageToSend)
	if err != nil {
		log.Fatalf("Gagal mengirim pesan: %v", err)
	}

	log.Printf("Berhasil mengirim %d bytes (termasuk 2 byte header) ke server.", len(messageToSend))
}
